-- Caso: Validar brackets (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0645
CREATE OR REPLACE FUNCTION solve_c0645(p_s text)
RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
  stack text := '';
  i integer := 1;
  n integer := length(p_s);
  ch text;
  top text;
BEGIN
  WHILE i <= n LOOP
    ch := substr(p_s, i, 1);

    IF ch IN ('(', '[', '{') THEN
      stack := stack || ch;
    ELSIF ch IN (')', ']', '}') THEN
      IF length(stack) = 0 THEN
        RETURN false;
      END IF;

      top := substr(stack, length(stack), 1);
      stack := substr(stack, 1, length(stack)-1);

      IF (top='(' AND ch<>')') OR (top='[' AND ch<>']') OR (top='{' AND ch<>'}') THEN
        RETURN false;
      END IF;
    END IF;

    i := i + 1;
  END LOOP;

  RETURN length(stack)=0;
END;
$$;

CREATE OR REPLACE PROCEDURE sp_solve_c0645(p_s text, INOUT p_out boolean)
LANGUAGE plpgsql
AS $$
BEGIN
  p_out := solve_c0645(p_s);
END;
$$;

